payslip_template_source = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8"/>\n<style>\n  @page {\n    size: A4;\n    margin: 20mm 15mm;\n    @top-center {\n      content: "Pay Slip — " string(page);\n      font-size: 9pt;\n      color: #888;\n    }\n  }\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n  body { font-family: DejaVu Sans, Arial, sans-serif; font-size: 11pt; color: #1a1a1a; }\n\n  .header { display: flex; align-items: flex-start; gap: 16px; margin-bottom: 18px; border-bottom: 2px solid #1a3c6e; padding-bottom: 12px; }\n  .org-logo { width: 72px; height: 72px; object-fit: contain; border: 1px solid #ddd; border-radius: 4px; }\n  .org-logo-placeholder { width: 72px; height: 72px; background: #f0f4fa; border: 1px solid #c0c8d8; border-radius: 4px; display: flex; align-items: center; justify-content: center; font-size: 9pt; color: #888; }\n  .org-info { flex: 1; }\n  .org-name { font-size: 18pt; font-weight: bold; color: #1a3c6e; }\n  .org-address { font-size: 9pt; color: #555; margin-top: 3px; line-height: 1.4; }\n  .org-cin { font-size: 8.5pt; color: #777; margin-top: 2px; }\n  .slip-meta { text-align: right; font-size: 9.5pt; }\n  .slip-meta .slip-num { font-weight: bold; color: #1a3c6e; font-size: 10pt; }\n  .slip-meta div { margin-bottom: 3px; }\n\n  .title-bar { background: #1a3c6e; color: white; text-align: center; padding: 6px 0; font-size: 13pt; font-weight: bold; letter-spacing: 1px; margin-bottom: 14px; border-radius: 3px; }\n\n  .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px 20px; margin-bottom: 14px; border: 1px solid #d0d8e8; border-radius: 4px; padding: 10px 12px; background: #f8fafd; }\n  .info-grid .label { font-size: 8.5pt; color: #666; }\n  .info-grid .value { font-size: 10pt; font-weight: 600; color: #1a1a1a; }\n\n  .days-bar { background: #eef3fb; border: 1px solid #c5d0e8; border-radius: 3px; padding: 4px 10px; font-size: 9.5pt; margin-bottom: 14px; text-align: center; color: #1a3c6e; }\n\n  .columns { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; margin-bottom: 14px; }\n  .section { border: 1px solid #c5d0e8; border-radius: 4px; overflow: hidden; }\n  .section-header { background: #1a3c6e; color: white; padding: 5px 10px; font-size: 9.5pt; font-weight: bold; letter-spacing: 0.5px; }\n  .section-header.right { background: #c0392b; }\n  table { width: 100%; border-collapse: collapse; }\n  th { font-size: 8.5pt; color: #555; text-align: left; padding: 4px 10px; background: #f0f4fa; border-bottom: 1px solid #d0d8e8; }\n  th.right { text-align: right; }\n  td { font-size: 9.5pt; padding: 3px 10px; }\n  td.right { text-align: right; font-variant-numeric: tabular-nums; }\n  tr.total-row td { border-top: 1.5px solid #1a3c6e; font-weight: bold; background: #f8fafd; }\n  tr.total-row td.right { color: #1a3c6e; }\n  tr.deduct-total td { border-top: 1.5px solid #c0392b; font-weight: bold; background: #fdf4f3; }\n  tr.deduct-total td.right { color: #c0392b; }\n\n  .employer-section { margin-bottom: 14px; }\n  .employer-header { background: #27ae60; color: white; padding: 5px 10px; font-size: 9.5pt; font-weight: bold; border-radius: 4px 4px 0 0; }\n  .employer-note { font-size: 8pt; color: #555; padding: 3px 10px; background: #f0f4fa; }\n\n  .tax-section { margin-bottom: 14px; }\n  .tax-header { background: #2c3e50; color: white; padding: 5px 10px; font-size: 9.5pt; font-weight: bold; border-radius: 4px 4px 0 0; }\n\n  .net-pay-box { background: #1a3c6e; color: white; text-align: center; padding: 12px; border-radius: 4px; margin-bottom: 14px; }\n  .net-pay-label { font-size: 9pt; letter-spacing: 1px; opacity: 0.85; margin-bottom: 4px; }\n  .net-pay-amount { font-size: 22pt; font-weight: bold; letter-spacing: 0.5px; }\n  .net-pay-words { font-size: 9pt; opacity: 0.7; margin-top: 3px; }\n\n  .footer { display: flex; align-items: flex-start; gap: 16px; margin-top: 10px; border-top: 1px solid #d0d8e8; padding-top: 10px; }\n  .qr-box { text-align: center; }\n  .qr-box img { width: 80px; height: 80px; }\n  .qr-box div { font-size: 7.5pt; color: #888; margin-top: 2px; }\n  .regime-box { font-size: 9pt; color: #555; }\n  .regime-box strong { color: #1a3c6e; }\n  .footer-note { font-size: 7.5pt; color: #aaa; text-align: right; flex: 1; line-height: 1.5; }\n</style>\n</head>\n<body>\n\n<div class="header">\n  {% if org_logo_url %}\n    <img src="{{ org_logo_url }}" class="org-logo" alt="Logo"/>\n  {% else %}\n    <div class="org-logo-placeholder">No Logo</div>\n  {% endif %}\n  <div class="org-info">\n    <div class="org-name">{{ org_name }}</div>\n    {% if org_address %}<div class="org-address">{{ org_address }}</div>{% endif %}\n    {% if org_cin %}<div class="org-cin">CIN: {{ org_cin }}</div>{% endif %}\n  </div>\n  <div class="slip-meta">\n    <div class="slip-num">{{ slip_number }}</div>\n    <div>Period: {{ period_label }}</div>\n    {% if payment_date %}<div>Paid on: {{ payment_date }}</div>{% endif %}\n  </div>\n</div>\n\n<div class="title-bar">PAY SLIP</div>\n\n{% if days_detail %}\n<div class="days-bar">Paid Days: {{ days_detail }}</div>\n{% endif %}\n\n<div class="info-grid">\n  <div><div class="label">Employee Name</div><div class="value">{{ employee_name }}</div></div>\n  <div><div class="label">Employee Code</div><div class="value">{{ employee_code }}</div></div>\n  <div><div class="label">Designation</div><div class="value">{{ designation }}</div></div>\n  <div><div class="label">Department</div><div class="value">{{ department }}</div></div>\n  <div><div class="label">PAN</div><div class="value">{{ pan }}</div></div>\n  <div><div class="label">UAN / ESI IP</div><div class="value">{{ uan }}{% if esi_ip and esi_ip != "N/A" %} / {{ esi_ip }}{% endif %}</div></div>\n</div>\n\n<div class="columns">\n  <div class="section">\n    <div class="section-header">EARNINGS</div>\n    <table>\n      <thead><tr><th>Component</th><th class="right">Amount (₹)</th></tr></thead>\n      <tbody>\n        {% for row in earnings_rows %}\n          <tr><td>{{ row.name }}</td><td class="right">{{ row.amount }}</td></tr>\n        {% endfor %}\n        <tr class="total-row"><td>Gross Salary</td><td class="right">{{ gross_salary }}</td></tr>\n      </tbody>\n    </table>\n  </div>\n  <div class="section">\n    <div class="section-header right">DEDUCTIONS</div>\n    <table>\n      <thead><tr><th>Component</th><th class="right">Amount (₹)</th></tr></thead>\n      <tbody>\n        {% for row in deductions_rows %}\n          <tr><td>{{ row.name }}</td><td class="right">{{ row.amount }}</td></tr>\n        {% endfor %}\n        <tr class="deduct-total"><td>Total Deductions</td><td class="right">{{ total_deductions }}</td></tr>\n      </tbody>\n    </table>\n  </div>\n</div>\n\n{% if employer_rows %}\n<div class="employer-section">\n  <div class="employer-header">EMPLOYER CONTRIBUTIONS (not deducted from pay)</div>\n  <table>\n    <thead><tr><th>Component</th><th class="right">Amount (₹)</th></tr></thead>\n    <tbody>\n      {% for row in employer_rows %}\n        <tr><td>{{ row.name }}</td><td class="right">{{ row.amount }}</td></tr>\n      {% endfor %}\n    </tbody>\n  </table>\n</div>\n{% endif %}\n\n{% if tax_rows %}\n<div class="tax-section">\n  <div class="tax-header">TAX COMPUTATION (Annual)</div>\n  <table>\n    <tbody>\n      {% for row in tax_rows %}\n        <tr><td>{{ row.label }}</td><td class="right">{{ row.value }}</td></tr>\n      {% endfor %}\n    </tbody>\n  </table>\n</div>\n{% endif %}\n\n<div class="net-pay-box">\n  <div class="net-pay-label">NET PAY (TAKE-HOME)</div>\n  <div class="net-pay-amount">{{ net_pay }}</div>\n</div>\n\n<div class="footer">\n  <div class="qr-box">\n    {% if qr_base64 %}<img src="data:image/png;base64,{{ qr_base64 }}" alt="QR"/>{% endif %}\n    <div>Verify at clarisal.com</div>\n  </div>\n  <div class="regime-box">\n    Tax Regime: <strong>{{ tax_regime }}</strong><br/>\n    Standard Deduction applied\n  </div>\n  <div class="footer-note">\n    This is a computer-generated payslip and does not require a signature.<br/>\n    For queries, contact your HR department.\n  </div>\n</div>\n\n</body>\n</html>'